Let's rewrite the `hashElementsVersion` so it can efficiently consume both arrays and maps:

```ts
export const hashElementsVersion = (elements: ElementsMapOrArray): number => {
  let hash = 5381;
  const _elements: Iterable<ExcalidrawElement> = Array.isArray(elements)
    ? elements
    : elements.values();
  for (const element of _elements) {
    hash = (hash << 5) + hash + element.versionNonce;
  }
  return hash >>> 0; // Ensure unsigned 32-bit integer
};
